#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=200005;
int n,m,dfn[N],low[N],vis[N],siz[N],id[N],cnt,cnt2;
int cnt3,pre[N],a[N],b[N];
char c[N][2];
string s;
stack<int> st;
vector<int> g[N];
unordered_map<int,bool> mp;
void tarjan(int u)
{
	low[u]=dfn[u]=++cnt;
	st.push(u);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(!dfn[v])
		{
			tarjan(v);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
	{
		cnt2++;
		int v;
		while(v=st.top())
		{
			vis[v]=0;
			id[v]=cnt2;
			siz[cnt2]++;
			st.pop();
			if(v==u) break;
		}
	}
}
bool fun(int num,char cc)
{
	char tmp=s[num];
	if(tmp=='c')
	{
		if(cc=='A') return 0;
		else return 1;
	}
	if(tmp=='b')
	{
		if(cc=='A') return 0;
		else return 1;
	}
	if(tmp=='a')
	{
		if(cc=='B') return 0;
		else return 1;
	}
	if(cc=='C') return 1;
	return 0;
}
char change(char cc)
{
	return cc-'a'+'A';
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>s>>m;
	s=" "+s;
	for(int i=1;i<=n;i++)
	{
		if(s[i]=='x') pre[i]=++cnt3;
	}
	for(int i=1;i<=m;i++)
	{
		cin>>a[i]>>c[i][0]>>b[i]>>c[i][1];
	}
	for(int j=0;j<(1<<cnt3);j++)
	{
		mp.clear();
		cnt=cnt2=0;
		while(!st.empty()) st.pop();
		for(int i=1;i<=2*n;i++)
		{
			low[i]=dfn[i]=id[i]=vis[i]=siz[i]=0;
		}
		for(int i=1;i<=m;i++)
		{
			//0 AC 1 BC
			int numa=(j&(1<<(pre[a[i]]-1)));//a[i]是否为 1 （BC） 
			int numb=(j&(1<<(pre[b[i]]-1)));//b[i]是否... 
			int flag1=fun(a[i],c[i][0]),flag2=fun(b[i],c[i][1]);
			if(s[a[i]]=='x'&&s[b[i]]=='x')
			{
				if((!numa)&&c[i][0]=='B') continue;//此条件为废话（不可能成立） 
				if(numa&&c[i][0]=='A') continue;//此条件为废话（不可能成立） 
				mp[a[i]+n*flag1]=1;
				if(!numb&&c[i][1]=='B')
				{
					g[a[i]+n*flag1].push_back(a[i]+n*(!flag1));
					continue;
				}
				if(numb&&c[i][1]=='A')
				{
					g[a[i]+n*flag1].push_back(a[i]+n*(!flag1));
					continue;
				}
				g[a[i]+n*flag1].push_back(b[i]+n*flag2);
				g[b[i]+n*(!flag2)].push_back(a[i]+n*(!flag1));
				mp[b[i]+n*(!flag2)]=1;
			}
			else if(s[a[i]]!='x'&&s[b[i]]=='x')
			{
				if(change(s[a[i]])==c[i][0]) continue;
				mp[a[i]+n*flag1]=1;
				if(!numb&&c[i][1]=='B')
				{
					g[a[i]+n*flag1].push_back(a[i]+n*(!flag1));
					continue;
				}
				if(numb&&c[i][1]=='A')
				{
					g[a[i]+n*flag1].push_back(a[i]+n*(!flag1));
					continue;
				}
				g[a[i]+n*flag1].push_back(b[i]+n*flag2);
				g[b[i]+n*(!flag2)].push_back(a[i]+n*(!flag1));
				mp[b[i]+n*(!flag2)]=1;
			}
			else if(s[a[i]]=='x'&&s[b[i]]!='x')
			{
				if(!numa&&c[i][0]=='B') continue;
				if(numa&&c[i][0]=='A') continue;
				mp[a[i]+n*flag1]=1;
				if(change(s[b[i]])==c[i][1])
				{
					g[a[i]+n*flag1].push_back(a[i]+n*(!flag1));
					continue;
				}
				g[a[i]+n*flag1].push_back(b[i]+n*flag2);
				g[b[i]+n*(!flag2)].push_back(a[i]+n*(!flag1));
				mp[b[i]+n*(!flag2)]=1;
			}
			else
			{
				if(change(s[a[i]])==c[i][0]) continue;
				mp[a[i]+n*flag1]=1;
				if(change(s[b[i]])==c[i][1])
				{
					g[a[i]+n*flag1].push_back(a[i]+n*(!flag1));
					continue;
				}
				g[a[i]+n*flag1].push_back(b[i]+n*flag2);
				g[b[i]+n*(!flag2)].push_back(a[i]+n*(!flag1));
				mp[b[i]+n*(!flag2)]=1;
			}
		}
		for(int i=1;i<=2*n;i++)
		{
			if(!dfn[i]) tarjan(i);
		}
		bool flag=1;
		for(int i=1;i<=n;i++)
		{
			if(id[i]==id[i+n])
			{
				flag=0;
				break;
			}
		}
		if(!flag) goto end;
		for(int i=1;i<=n;i++)
		{
			if(s[i]=='x')
			{
				if(!(j&(1<<(pre[i]-1))))
				{
					if(id[i]>id[i+n]) cout<<"C";
					else cout<<"A";
				}
				else
				{
					if(id[i]>id[i+n])	cout<<"C";
					else cout<<"B";
				}
			}
			else
			{
				if(s[i]=='a')
				{
					if(id[i]>id[i+n]) cout<<"C";
					else cout<<"B";
				}
				else if(s[i]=='b')
				{
					if(id[i]>id[i+n]) cout<<"C";
					else cout<<"A";
				}
				else
				{
					if(id[i]>id[i+n]) cout<<"B";
					else cout<<"A";
				}
			}
		}
		return 0;
		end: ;
		for(auto it=mp.begin();it!=mp.end();it++)
		{
			g[it->first].clear();
		}
	}
	cout<<"-1";
	return 0;
}
